// // This module implements a 4-bit Johnson counter with active-high reset.
module Johnson_counter_4(
   input                clk,
   input                rst_n,
   output reg [3:0]     Q  
);
    always@(posedge clk or negedge rst_n)begin
        if(!rst_n) Q <= 4'b0000;
        else Q <= {~Q[3], Q[3:1]};
    end
endmodule
